export interface TarotCard {
  id: string;
  nameEn: string;
  nameZh: string;
  type: 'major' | 'minor';
  suit?: 'wands' | 'cups' | 'swords' | 'pentacles';
  number?: number;
  image: string; // Placeholder URL
}

export interface DrawResult {
  cardId: string;
  isReversed: boolean;
  position: number; // 0, 1, 2
}

export interface DeckCardState {
  id: string; // Unique ID for this instance in the deck (not just card definition ID)
  definitionId: string;
  isReversed: boolean;
  angle: number; // For circular layout
}

import { TarotCard } from './types';

// Helper to generate placeholder image URL
const getPlaceholder = (id: string) => `https://picsum.photos/seed/${id}/300/500`;

export const MAJOR_ARCANA: TarotCard[] = [
  { id: 'm00', nameEn: 'The Fool', nameZh: '愚者', type: 'major', image: getPlaceholder('m00') },
  { id: 'm01', nameEn: 'The Magician', nameZh: '魔术师', type: 'major', image: getPlaceholder('m01') },
  { id: 'm02', nameEn: 'The High Priestess', nameZh: '女祭司', type: 'major', image: getPlaceholder('m02') },
  { id: 'm03', nameEn: 'The Empress', nameZh: '皇后', type: 'major', image: getPlaceholder('m03') },
  { id: 'm04', nameEn: 'The Emperor', nameZh: '皇帝', type: 'major', image: getPlaceholder('m04') },
  { id: 'm05', nameEn: 'The Hierophant', nameZh: '教皇', type: 'major', image: getPlaceholder('m05') },
  { id: 'm06', nameEn: 'The Lovers', nameZh: '恋人', type: 'major', image: getPlaceholder('m06') },
  { id: 'm07', nameEn: 'The Chariot', nameZh: '战车', type: 'major', image: getPlaceholder('m07') },
  { id: 'm08', nameEn: 'Strength', nameZh: '力量', type: 'major', image: getPlaceholder('m08') },
  { id: 'm09', nameEn: 'The Hermit', nameZh: '隐士', type: 'major', image: getPlaceholder('m09') },
  { id: 'm10', nameEn: 'Wheel of Fortune', nameZh: '命运之轮', type: 'major', image: getPlaceholder('m10') },
  { id: 'm11', nameEn: 'Justice', nameZh: '正义', type: 'major', image: getPlaceholder('m11') },
  { id: 'm12', nameEn: 'The Hanged Man', nameZh: '倒吊人', type: 'major', image: getPlaceholder('m12') },
  { id: 'm13', nameEn: 'Death', nameZh: '死神', type: 'major', image: getPlaceholder('m13') },
  { id: 'm14', nameEn: 'Temperance', nameZh: '节制', type: 'major', image: getPlaceholder('m14') },
  { id: 'm15', nameEn: 'The Devil', nameZh: '恶魔', type: 'major', image: getPlaceholder('m15') },
  { id: 'm16', nameEn: 'The Tower', nameZh: '高塔', type: 'major', image: getPlaceholder('m16') },
  { id: 'm17', nameEn: 'The Star', nameZh: '星星', type: 'major', image: getPlaceholder('m17') },
  { id: 'm18', nameEn: 'The Moon', nameZh: '月亮', type: 'major', image: getPlaceholder('m18') },
  { id: 'm19', nameEn: 'The Sun', nameZh: '太阳', type: 'major', image: getPlaceholder('m19') },
  { id: 'm20', nameEn: 'Judgement', nameZh: '审判', type: 'major', image: getPlaceholder('m20') },
  { id: 'm21', nameEn: 'The World', nameZh: '世界', type: 'major', image: getPlaceholder('m21') },
];

const suits: Array<'wands' | 'cups' | 'swords' | 'pentacles'> = ['wands', 'cups', 'swords', 'pentacles'];
const suitNamesZh = { wands: '权杖', cups: '圣杯', swords: '宝剑', pentacles: '星币' };

export const MINOR_ARCANA: TarotCard[] = [];

suits.forEach(suit => {
  for (let i = 1; i <= 14; i++) {
    let nameEn = '';
    let nameZh = '';
    const suitName = suit.charAt(0).toUpperCase() + suit.slice(1);
    const suitZh = suitNamesZh[suit];

    if (i <= 10) {
      nameEn = `${i === 1 ? 'Ace' : i} of ${suitName}`;
      nameZh = `${suitZh} ${i === 1 ? '首牌' : i}`;
    } else {
      const courts = ['Page', 'Knight', 'Queen', 'King'];
      const courtsZh = ['侍从', '骑士', '皇后', '国王'];
      nameEn = `${courts[i - 11]} of ${suitName}`;
      nameZh = `${suitZh}${courtsZh[i - 11]}`;
    }

    MINOR_ARCANA.push({
      id: `${suit[0]}${i}`,
      nameEn,
      nameZh,
      type: 'minor',
      suit,
      number: i,
      image: getPlaceholder(`${suit[0]}${i}`)
    });
  }
});

export const ALL_CARDS = [...MAJOR_ARCANA, ...MINOR_ARCANA];

export const TOTAL_CARDS = ALL_CARDS.length;

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'outline';
}

export const Button: React.FC<ButtonProps> = ({ 
  className = '', 
  variant = 'primary', 
  children, 
  ...props 
}) => {
  const baseStyles = "relative px-8 py-3 font-serif text-lg tracking-widest uppercase transition-all duration-300 transform border hover:scale-105 active:scale-95 disabled:opacity-50 disabled:pointer-events-none";

  const variants = {
    primary: "bg-gold text-background border-gold hover:bg-gold-light hover:shadow-[0_0_15px_rgba(212,175,55,0.5)]",
    outline: "bg-transparent text-gold border-gold hover:bg-gold/10"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      {...props}
    >
      <span className="relative z-10 flex items-center justify-center gap-2">
        {children}
      </span>
    </button>
  );
};

import React from 'react';
import { motion } from 'framer-motion';

interface TarotCardProps {
  isFlipped?: boolean;
  isReversed?: boolean;
  image?: string;
  onClick?: () => void;
  className?: string;
  style?: React.CSSProperties;
  layoutId?: string;
  width?: number;
  height?: number;
}

export const TarotCard: React.FC<TarotCardProps> = ({
  isFlipped = false,
  isReversed = false,
  image,
  onClick,
  className = '',
  style,
  layoutId,
  width = 150,
  height = 250
}) => {
  return (
    <motion.div
      layoutId={layoutId}
      className={`relative cursor-pointer perspective-1000 ${className}`}
      style={{ width, height, ...style }}
      onClick={onClick}
      initial={false}
      animate={{ rotate: isReversed && isFlipped ? 180 : 0 }}
      transition={{ duration: 0.5 }}
    >
      <motion.div
        className="w-full h-full relative preserve-3d transition-transform duration-700"
        style={{ transformStyle: 'preserve-3d', transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)' }}
      >
        {/* Card Back */}
        <div 
          className="absolute inset-0 w-full h-full backface-hidden rounded-lg border-2 border-gold/30 bg-surface shadow-xl overflow-hidden"
          style={{ backfaceVisibility: 'hidden' }}
        >
          <div className="w-full h-full bg-[url('https://www.transparenttextures.com/patterns/black-scales.png')] opacity-50"></div>
          <div className="absolute inset-2 border border-gold/20 rounded opacity-80 flex items-center justify-center">
             <div className="w-16 h-16 border-2 border-gold/40 rotate-45"></div>
          </div>
        </div>

        {/* Card Front */}
        <div 
          className="absolute inset-0 w-full h-full backface-hidden rounded-lg bg-surface shadow-xl overflow-hidden border-2 border-gold"
          style={{ backfaceVisibility: 'hidden', transform: 'rotateY(180deg)' }}
        >
          {image ? (
            <img src={image} alt="Tarot Card" className="w-full h-full object-cover" />
          ) : (
            <div className="w-full h-full flex items-center justify-center bg-gray-800 text-gold">
              Loading...
            </div>
          )}
          {/* Overlay to hint reversibility if needed, usually subtle */}
        </div>
      </motion.div>
    </motion.div>
  );
};

