// Helper for Major Arcana: ar00.jpg to ar21.jpg
const getMajorImage = (id: string) => {
  const numPart = id.slice(1); // '00', '01' ... '21'
  return `${IMG_BASE_URL}/ar${numPart}.jpg`;
};

export const MAJOR_ARCANA: TarotCard[] = [
  { id: 'm00', nameEn: 'The Fool', nameZh: '愚者', type: 'major', image: getMajorImage('m00') },
  { id: 'm01', nameEn: 'The Magician', nameZh: '魔术师', type: 'major', image: getMajorImage('m01') },
