  { id: 'm03', nameEn: 'The Empress', nameZh: '皇后', type: 'major', image: getMajorImage('m03') },
  { id: 'm04', nameEn: 'The Emperor', nameZh: '皇帝', type: 'major', image: getMajorImage('m04') },
  { id: 'm05', nameEn: 'The Hierophant', nameZh: '教皇', type: 'major', image: getMajorImage('m05') },
  { id: 'm06', nameEn: 'The Lovers', nameZh: '恋人', type: 'major', image: getMajorImage('m06') },
  { id: 'm07', nameEn: 'The Chariot', nameZh: '战车', type: 'major', image: getMajorImage('m07') },
  { id: 'm08', nameEn: 'Strength', nameZh: '力量', type: 'major', image: getMajorImage('m08') },
  { id: 'm09', nameEn: 'The Hermit', nameZh: '隐士', type: 'major', image: getMajorImage('m09') },
