// Helper for Minor Arcana images
const getMinorImage = (suit: string, number: number) => {
  const suitPrefixs: Record<string, string> = {
    wands: 'wa',
    cups: 'cu',
    swords: 'sw',
    pentacles: 'pe'
  };

  const prefix = suitPrefixs[suit];
  let suffix = '';

  if (number === 1) suffix = 'ac';
  else if (number <= 10) suffix = String(number).padStart(2, '0');
  else if (number === 11) suffix = 'pa';
  else if (number === 12) suffix = 'kn';
  else if (number === 13) suffix = 'qu';
  else if (number === 14) suffix = 'ki';

  return `${IMG_BASE_URL}/${prefix}${suffix}.jpg`;
};

