import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence, useAnimation } from 'framer-motion';
import { ALL_CARDS } from '../constants';
import { TarotCard } from './TarotCard';
import { DeckCardState, DrawResult } from '../types';

// Constants for layout
const CIRCLE_RADIUS_X = 600; // Ellipse width radius
const CIRCLE_RADIUS_Y = 150; // Ellipse height radius (3D effect)
const VISIBLE_CARDS = 78;

const DrawScreen: React.FC = () => {
  const navigate = useNavigate();
  const [deck, setDeck] = useState<DeckCardState[]>([]);
  const [drawnCards, setDrawnCards] = useState<DrawResult[]>([]);
  const [rotation, setRotation] = useState(0);
  const rotationRef = useRef(0);
  const autoRotateRef = useRef<number | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const lastX = useRef(0);

  // Initialize deck
  useEffect(() => {
    // Shuffle and init
    const shuffled = [...ALL_CARDS]
      .sort(() => Math.random() - 0.5)
      .map((card, index) => ({
        id: `card-${index}`,
        definitionId: card.id,
        isReversed: Math.random() > 0.5,
        angle: (index / 78) * 360
      }));
    setDeck(shuffled);
  }, []);

  // Auto rotation
  useEffect(() => {
    const animate = () => {
      if (!isDragging.current && drawnCards.length < 3) {
        rotationRef.current += 0.05;
        setRotation(rotationRef.current);
      }
      autoRotateRef.current = requestAnimationFrame(animate);
    };
    animate();
    return () => {
      if (autoRotateRef.current) cancelAnimationFrame(autoRotateRef.current);
    };
  }, [drawnCards.length]);

  const handleDragStart = (e: React.MouseEvent | React.TouchEvent) => {
    isDragging.current = true;
    lastX.current = 'touches' in e ? e.touches[0].clientX : e.clientX;
  };

  const handleDragMove = useCallback((e: MouseEvent | TouchEvent) => {
    if (!isDragging.current) return;
    const clientX = 'touches' in e ? (e as TouchEvent).touches[0].clientX : (e as MouseEvent).clientX;
    const delta = clientX - lastX.current;
    rotationRef.current += delta * 0.2;
    setRotation(rotationRef.current);
    lastX.current = clientX;
  }, []);

  const handleDragEnd = useCallback(() => {
    isDragging.current = false;
  }, []);

  useEffect(() => {
    window.addEventListener('mousemove', handleDragMove);
    window.addEventListener('mouseup', handleDragEnd);
    window.addEventListener('touchmove', handleDragMove);
    window.addEventListener('touchend', handleDragEnd);
    return () => {
      window.removeEventListener('mousemove', handleDragMove);
      window.removeEventListener('mouseup', handleDragEnd);
      window.removeEventListener('touchmove', handleDragMove);
      window.removeEventListener('touchend', handleDragEnd);
    };
  }, [handleDragMove, handleDragEnd]);

  const handleCardClick = (cardState: DeckCardState) => {
    if (drawnCards.length >= 3) return;
    if (drawnCards.find(c => c.cardId === cardState.definitionId)) return;

    // Add to drawn cards
    const newResult: DrawResult = {
      cardId: cardState.definitionId,
      isReversed: cardState.isReversed,
      position: drawnCards.length
    };

    const newDrawn = [...drawnCards, newResult];
    setDrawnCards(newDrawn);

    // Remove from visible circle deck locally to avoid re-clicking
    setDeck(prev => prev.filter(c => c.id !== cardState.id));

    if (newDrawn.length === 3) {
      setTimeout(() => {
        navigate('/result', { state: { results: newDrawn } });
      }, 1500);
    }
  };

  return (
    <div className="min-h-screen w-full bg-background overflow-hidden relative flex flex-col">
      {/* Top Slots */}
      <div className="h-1/3 w-full flex items-center justify-center gap-4 md:gap-8 pt-10 z-20 pointer-events-none">
        {[0, 1, 2].map((i) => {
          const result = drawnCards.find(r => r.position === i);
          return (
            <div 
              key={i} 
              className="relative border border-gold/30 rounded-lg bg-surface/50"
              style={{ width: 100, height: 175 }} // Ratio: 0.57
            >
              <div className="absolute -top-6 left-0 w-full text-center text-gold/50 text-sm font-serif">
                {['Past', 'Present', 'Future'][i]}
              </div>
              {result && (
                <motion.div
                  layoutId={`card-${result.cardId}`}
                  className="w-full h-full"
                  transition={{ type: "spring", stiffness: 300, damping: 30 }}
                >
                  <TarotCard 
                    width={100} 
                    height={175} 
                    isFlipped={false} // Keep face down until result
                  />
                </motion.div>
              )}
            </div>
          );
        })}
      </div>

      {/* Interactive Circle */}
      <div 
        className="flex-1 w-full relative flex items-center justify-center perspective-[1000px]"
        ref={containerRef}
        onMouseDown={handleDragStart}
        onTouchStart={handleDragStart}
      >
        <div className="relative w-full h-full flex items-center justify-center transform-style-3d md:mt-20">
          <AnimatePresence>
            {deck.map((card, i) => {
              // Calculate position in circle
              const theta = ((card.angle + rotation) % 360) * (Math.PI / 180);
              const x = Math.cos(theta) * CIRCLE_RADIUS_X;
              const y = Math.sin(theta) * CIRCLE_RADIUS_Y;
              const scale = (y + CIRCLE_RADIUS_Y * 2) / (CIRCLE_RADIUS_Y * 3); // Scale based on depth
              const zIndex = Math.floor(scale * 100);
              const opacity = scale < 0.6 ? 0.3 : 1; // Fade out back cards

              // Only render cards that are somewhat visible/relevant to performance
              if (scale < 0.4) return null;

              return (
                <motion.div
                  key={card.id}
                  layoutId={`card-${card.definitionId}`}
                  className="absolute cursor-pointer will-change-transform"
                  style={{
                    x,
                    y,
                    zIndex,
                    opacity,
                    scale: scale * 0.8, // Base scale adjustment
                  }}
                  onClick={(e) => {
                    e.stopPropagation();
                    handleCardClick(card);
                  }}
                  whileHover={{ scale: scale * 0.9, y: y - 20 }}
                >
                  <TarotCard width={100} height={175} />
                </motion.div>
              );
            })}
          </AnimatePresence>
        </div>
      </div>

      {/* Guide Text */}
      <div className="absolute bottom-10 w-full text-center pointer-events-none">
        <p className="text-gold/60 font-serif text-lg animate-pulse">
          {drawnCards.length < 3 ? "Drag to rotate, tap to select" : "Reading the stars..."}
        </p>
      </div>
    </div>
  );
};

export default DrawScreen;

import React, { useEffect, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ALL_CARDS } from '../constants';
import { DrawResult, TarotCard as TarotCardType } from '../types';
import { TarotCard } from './TarotCard';
import { Button } from './ui/Button';
import { RefreshCw } from 'lucide-react';

const ResultScreen: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const results = (location.state as { results: DrawResult[] })?.results || [];
  const [revealed, setRevealed] = useState<boolean[]>([false, false, false]);

  useEffect(() => {
    if (results.length === 0) {
      navigate('/');
    }
    // Sequential reveal
    results.forEach((_, i) => {
      setTimeout(() => {
        setRevealed(prev => {
          const next = [...prev];
          next[i] = true;
          return next;
        });
      }, (i + 1) * 800);
    });
  }, [results, navigate]);

  const getCardDetails = (id: string): TarotCardType | undefined => {
    return ALL_CARDS.find(c => c.id === id);
  };

  const positions = ['The Past', 'The Present', 'The Future'];

  return (
    <div className="min-h-screen w-full bg-background flex flex-col items-center py-10 overflow-y-auto">
      <motion.h2 
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="font-display text-4xl text-gold mb-12 mt-4"
      >
        Your Reading
      </motion.h2>

      <div className="flex flex-col md:flex-row gap-12 md:gap-8 items-center justify-center w-full max-w-6xl px-4 mb-12">
        {results.map((result, index) => {
          const card = getCardDetails(result.cardId);
          if (!card) return null;

          return (
            <div key={result.cardId} className="flex flex-col items-center gap-6">
              <div className="relative group perspective-1000">
                <motion.div
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: index * 0.2 }}
                >
                  <TarotCard 
                    isFlipped={revealed[index]}
                    isReversed={result.isReversed}
                    image={card.image}
                    width={200}
                    height={350} // Ratio approx 0.57
                    className="shadow-[0_0_30px_rgba(212,175,55,0.15)] transition-shadow duration-500 hover:shadow-[0_0_50px_rgba(212,175,55,0.3)]"
                  />
                </motion.div>
              </div>

              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: revealed[index] ? 1 : 0 }}
                transition={{ duration: 1 }}
                className="text-center space-y-2"
              >
                <div className="text-gold/60 font-serif text-sm uppercase tracking-widest border-b border-gold/20 pb-1 mb-2">
                  {positions[index]}
                </div>
                <h3 className="text-2xl text-gold font-display">{card.nameEn}</h3>
                <p className="text-lg text-gold/80 font-serif">{card.nameZh}</p>
                {result.isReversed && (
                  <span className="inline-block px-2 py-0.5 text-xs border border-red-900/50 bg-red-900/10 text-red-400 rounded">
                    Reversed (逆位)
                  </span>
                )}
              </motion.div>
            </div>
          );
        })}
      </div>

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 3 }}
        className="mt-auto pb-10"
      >
        <Button onClick={() => navigate('/draw')} variant="outline">
          <RefreshCw className="w-4 h-4 mr-2" />
          Draw Again
        </Button>
      </motion.div>
    </div>
  );
};

