  const lastX = useRef(0);

  // Star background state
  const [stars, setStars] = useState<Array<{id: number, top: number, left: number, size: number, delay: number, duration: number}>>([]);

  // Responsive Radii
  const [radii, setRadii] = useState({ x: 300, y: 80 });

  // Initialize stars for background
  useEffect(() => {
    const newStars = Array.from({ length: 150 }).map((_, i) => ({
      id: i,
      top: Math.random() * 100,
      left: Math.random() * 100,
      size: Math.random() < 0.8 ? 1.5 : 3, // mostly small stars, some larger
      delay: Math.random() * 5,
      duration: Math.random() * 3 + 2 // 2s to 5s duration
    }));
    setStars(newStars);
