    setDeck(prev => prev.filter(c => c.id !== cardState.id));

    if (newDrawn.length === 3) {
      setTimeout(() => {
        navigate('/result', { state: { results: newDrawn } });
      }, 1500);
    }
  };

  return (
    <div className="min-h-screen w-full bg-[#0f0f12] overflow-hidden relative flex flex-col">
      {/* Background Starfield effect */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {/* Subtle Nebula/Gradient base */}
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-mystic-purple/20 via-background to-background opacity-60"></div>

        {/* Generated Stars */}
        {stars.map((star) => (
          <div
            key={star.id}
            className="absolute bg-white rounded-full opacity-0 animate-pulse"
            style={{
              top: `${star.top}%`,
              left: `${star.left}%`,
              width: `${star.size}px`,
              height: `${star.size}px`,
              animationDelay: `${star.delay}s`,
              animationDuration: `${star.duration}s`,
              opacity: Math.random() * 0.5 + 0.3 // base opacity variation
            }}
          />
        ))}
      </div>

      {/* Return Button */}
      <button
        onClick={() => navigate('/')}
        className="absolute top-6 left-6 z-50 flex items-center gap-2 text-gold/60 hover:text-gold transition-colors group"
      >
        <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
        <span className="font-serif tracking-widest uppercase text-sm">Home</span>
      </button>

      {/* Top Slots */}
      <div className="h-[25vh] w-full flex items-end justify-center gap-4 md:gap-8 pb-4 z-20 pointer-events-none">
        {[0, 1, 2].map((i) => {
          const result = drawnCards.find(r => r.position === i);
          return (
            <div 
              key={i} 
              className="relative border border-gold/30 rounded-lg bg-surface/50 backdrop-blur-sm transition-all duration-500"
              style={{ 
                width: 80, 
                height: 140,
                borderColor: result ? '#d4af37' : 'rgba(212,175,55,0.3)' 
              }} 
            >
              <div className="absolute -top-6 left-0 w-full text-center text-gold/50 text-xs font-serif uppercase tracking-widest">
                {['Past', 'Present', 'Future'][i]}
              </div>
              {result && (
                <motion.div
                  layoutId={`card-${result.cardId}`}
                  className="w-full h-full"
                  transition={{ type: "spring", stiffness: 300, damping: 30 }}
                >
                  <TarotCard 
                    width={80} 
                    height={140} 
                    isFlipped={false} // Keep face down until result
                  />
                </motion.div>
              )}
            </div>
          );
        })}
      </div>

      {/* Interactive Orbit Center */}
      <div 
