        <div className="shooting-star-layer" style={{ top: '10%', right: '10%' }}></div>
        <div className="shooting-star-layer" style={{ top: '20%', right: '30%', animationDelay: '12s', animationDuration: '10s' }}></div>
      </div>

      {/* Return Button */}
      <button
        onClick={() => navigate('/')}
        className="absolute top-6 left-6 z-50 flex items-center gap-2 text-gold/60 hover:text-gold transition-colors group"
      >
        <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
        <span className="font-serif tracking-widest uppercase text-sm">Home</span>
      </button>

      {/* Top Slots */}
      <div className="h-[25vh] w-full flex items-end justify-center gap-4 md:gap-8 pb-4 z-20 pointer-events-none">
        {[0, 1, 2].map((i) => {
          const result = drawnCards.find(r => r.position === i);
          return (
            <div 
              key={i} 
              className="relative border border-gold/30 rounded-lg bg-surface/50 backdrop-blur-sm transition-all duration-500"
              style={{ 
                width: 80, 
                height: 140,
                borderColor: result ? '#d4af37' : 'rgba(212,175,55,0.3)' 
              }} 
            >
              <div className="absolute -top-6 left-0 w-full text-center text-gold/50 text-xs font-serif uppercase tracking-widest">
                {['Past', 'Present', 'Future'][i]}
              </div>
              {result && (
                <motion.div
                  layoutId={`card-${result.cardId}`}
                  className="w-full h-full"
                  transition={{ type: "spring", stiffness: 300, damping: 30 }}
                >
                  <TarotCard 
                    width={80} 
                    height={140} 
                    isFlipped={false} // Keep face down until result
                  />
                </motion.div>
              )}
            </div>
          );
        })}
      </div>

      {/* Interactive Orbit Center */}
      <div 
        className="flex-1 w-full relative flex items-center justify-center perspective-[1000px] overflow-hidden"
        ref={containerRef}
        onMouseDown={handleDragStart}
        onTouchStart={handleDragStart}
      >
        {/* The "Earth" / Central Gravity Point */}
        <div className="absolute z-10 pointer-events-none flex flex-col items-center justify-center">
             {/* Glowing Core */}
             <div className="w-32 h-32 rounded-full bg-radial-gold blur-3xl opacity-30 absolute"></div>
             <div className="w-1 h-1 rounded-full bg-[#fff] shadow-[0_0_25px_#d4af37] relative z-10"></div>

             {/* Subtle Orbital Rings */}
             <div className="w-48 h-48 rounded-full border border-gold/5 absolute animate-[spin_30s_linear_infinite] opacity-50"></div>
             <div className="w-80 h-80 rounded-full border border-dashed border-gold/5 absolute animate-[spin_60s_linear_infinite_reverse] opacity-30"></div>
        </div>

