        <p className="text-gold/60 font-serif text-sm md:text-lg animate-pulse flex items-center justify-center gap-2">
          {drawnCards.length < 3 ? "The stars await. Select your destiny." : "Interpreting..."}
        </p>
      </div>
    </div>
  );
};

