            key={star.id}
            className="absolute rounded-full star-anim"
            style={{
              top: `${star.top}%`,
              left: `${star.left}%`,
              width: `${star.size}px`,
              height: `${star.size}px`,
              backgroundColor: star.color,
              opacity: star.baseOpacity,
              boxShadow: star.hasGlow ? `0 0 ${star.size * 2}px ${star.color}` : 'none',
              '--twinkle-duration': `${star.duration}s`,
              '--twinkle-delay': `${star.delay}s`
            } as React.CSSProperties}
          />
        ))}
      </div>

      {/* Return Button */}
      <button
        onClick={() => navigate('/')}
        className="absolute top-6 left-6 z-50 flex items-center gap-2 text-gold/60 hover:text-gold transition-colors group"
      >
        <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
        <span className="font-serif tracking-widest uppercase text-sm">Home</span>
      </button>

      {/* Top Slots - Moved down with mt-20 to be below the Home button */}
      <div className="mt-24 w-full flex items-center justify-center gap-4 md:gap-8 pb-4 z-20 pointer-events-none">
        {[0, 1, 2].map((i) => {
          const result = drawnCards.find(r => r.position === i);
          return (
            <div 
              key={i} 
              className="relative border border-gold/30 rounded-lg bg-surface/50 backdrop-blur-sm transition-all duration-500"
              style={{ 
                width: 80, 
                height: 140,
                borderColor: result ? '#d4af37' : 'rgba(212,175,55,0.3)' 
              }} 
            >
              <div className="absolute -top-6 left-0 w-full text-center text-gold/50 text-xs font-serif uppercase tracking-widest">
                {['Past', 'Present', 'Future'][i]}
              </div>
              {result && (
                <motion.div
                  layoutId={`card-${result.cardId}`}
                  className="w-full h-full"
                  transition={{ type: "spring", stiffness: 300, damping: 30 }}
                >
                  <TarotCard 
                    width={80} 
                    height={140} 
                    isFlipped={false} // Keep face down until result
                  />
                </motion.div>
              )}
            </div>
          );
        })}
      </div>

      {/* Interactive Orbit Center */}
      <div 
        className="flex-1 w-full relative flex items-center justify-center perspective-[1000px] overflow-hidden"
        ref={containerRef}
        onMouseDown={handleDragStart}
        onTouchStart={handleDragStart}
      >
        {/* The "Earth" / Central Gravity Point */}
        <div className="absolute z-10 pointer-events-none flex flex-col items-center justify-center -translate-y-16">
             {/* Glowing Core */}
             <div className="w-32 h-32 rounded-full bg-radial-gold blur-3xl opacity-30 absolute"></div>
             <div className="w-1 h-1 rounded-full bg-[#fff] shadow-[0_0_25px_#d4af37] relative z-10"></div>

             {/* Subtle Orbital Rings */}
             <div className="w-48 h-48 rounded-full border border-gold/5 absolute animate-[spin_30s_linear_infinite] opacity-50"></div>
             <div className="w-80 h-80 rounded-full border border-dashed border-gold/5 absolute animate-[spin_60s_linear_infinite_reverse] opacity-30"></div>
        </div>

        {/* Orbiting Cards */}
        <div className="relative w-full h-full flex items-center justify-center transform-style-3d -translate-y-16">
          <AnimatePresence>
            {deck.map((card) => {
              // Calculate 3D Orbit Position
              const theta = ((card.angle + rotation) % 360) * (Math.PI / 180);

              // x = Horizontal, y = Depth (Vertical in 3D projection)
              const x = Math.cos(theta) * radii.x;
              const zDepth = Math.sin(theta) * radii.y; 

              // Project 3D zDepth to 2D y-axis for the "tilted ring" look
              // If y is positive (front), it's lower on screen. If y is negative (back), it's higher.
              const y = zDepth; 

              // Scale based on "depth" (zDepth)
              // Front cards (positive zDepth) should be larger
              const scale = (zDepth + radii.y * 3) / (radii.y * 3.5); 

              // Opacity: Back cards fade out
              const opacity = scale < 0.7 ? 0.4 : 1; 

              // Z-Index: Front cards must be on top
              const zIndex = Math.floor(zDepth * 100);

              // Don't render cards far in back to save resources / improve aesthetics
              if (scale < 0.5) return null;

              return (
                <motion.div
                  key={card.id}
                  layoutId={`card-${card.definitionId}`}
                  className="absolute cursor-pointer will-change-transform flex flex-col items-center justify-center"
                  style={{
                    x, // Horizontal position
                    y, // Vertical tilt position
                    zIndex,
                    opacity,
                    scale: scale, 
                  }}
                  onClick={(e) => {
                    e.stopPropagation();
                    handleCardClick(card);
                  }}
                  whileHover={{ 
                    scale: scale * 1.1,
                    y: y - 20,
                    zIndex: zIndex + 1000 // Ensure hovered card pops to very front
                  }}
                >
                  <TarotCard width={100} height={175} />

                  {/* Reflection/Shadow for 3D grounding */}
                  <div 
                    className="absolute -bottom-4 w-[80%] h-2 bg-black/50 blur-sm rounded-full pointer-events-none" 
                    style={{ opacity: scale * 0.5 }}
                  />
                </motion.div>
              );
            })}
          </AnimatePresence>
        </div>
      </div>

      {/* Guide Text */}
      <div className="absolute bottom-10 w-full text-center pointer-events-none z-30">
        <p className="text-gold/60 font-serif text-sm md:text-lg animate-pulse flex items-center justify-center gap-2">
          {drawnCards.length < 3 ? "The stars await. Select your destiny." : "Interpreting..."}
        </p>
      </div>
    </div>
  );
};

