import React from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ArrowLeft } from 'lucide-react';
import { ALL_CARDS } from '../constants';
import { DrawResult, TarotCard as TarotCardType } from '../types';
import { TarotCard } from './TarotCard';

const InterpretationScreen: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const results = (location.state as { results: DrawResult[] })?.results || [];

  // If accessed directly without cards, redirect home
  React.useEffect(() => {
    if (!results || results.length === 0) {
      navigate('/');
    }
  }, [results, navigate]);

  const getCardDetails = (id: string): TarotCardType | undefined => {
    return ALL_CARDS.find(c => c.id === id);
  };

  return (
    <div className="min-h-screen w-full bg-background flex flex-col relative overflow-hidden">
      {/* Background Ambience */}
      <div className="absolute inset-0 pointer-events-none">
         <div className="absolute top-[-20%] left-[-10%] w-[600px] h-[600px] bg-gold/5 rounded-full blur-[100px]"></div>
         <div className="absolute bottom-[-20%] right-[-10%] w-[500px] h-[500px] bg-mystic-purple/20 rounded-full blur-[100px]"></div>
         <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] opacity-10"></div>
      </div>

      {/* Header */}
      <div className="p-6 z-20 flex items-center justify-between border-b border-gold/10 bg-background/50 backdrop-blur-sm sticky top-0">
        <button 
          onClick={() => navigate(-1)}
          className="flex items-center gap-2 text-gold/60 hover:text-gold transition-colors group"
        >
          <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
          <span className="font-serif tracking-widest uppercase text-sm">Back</span>
        </button>
        <h1 className="font-display text-xl text-gold tracking-wide">Interpretation</h1>
        <div className="w-20"></div> {/* Spacer for centering */}
      </div>

      <div className="flex-1 overflow-y-auto z-10 p-6 md:p-10 flex flex-col lg:flex-row gap-8 max-w-7xl mx-auto w-full">

        {/* Left Column: Summary of Cards */}
        <div className="lg:w-1/3 flex flex-col gap-4">
          <h2 className="text-gold/50 font-serif uppercase tracking-widest text-sm mb-2">The Spread</h2>
          <div className="flex flex-col gap-4">
            {results.map((result, idx) => {
              const card = getCardDetails(result.cardId);
              if (!card) return null;
              return (
                <motion.div 
                  key={idx}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: idx * 0.1 }}
                  className="flex items-center gap-4 bg-surface/50 p-3 rounded border border-gold/20 hover:bg-gold/5 transition-colors"
                >
                  <div className="w-12 h-20 flex-shrink-0">
                     <TarotCard 
                        width={48} 
                        height={80} 
                        image={card.image} 
                        isFlipped={true} 
                        isReversed={result.isReversed} 
                      />
                  </div>
                  <div>
                    <div className="text-gold/40 text-xs font-serif uppercase tracking-widest">Card {idx + 1}</div>
                    <div className="text-gold font-display text-lg">{card.nameEn}</div>
                    <div className="text-gold/60 text-xs italic">
                      {result.isReversed ? 'Reversed' : 'Upright'} • {card.nameZh}
                    </div>
                  </div>
                </motion.div>
              );
            })}
          </div>
        </div>

        {/* Right Column: AI Interpretation */}
        <div className="lg:w-2/3 flex flex-col">
            <h2 className="text-gold/50 font-serif uppercase tracking-widest text-sm mb-4 flex items-center gap-2">
                Cosmic Insight
            </h2>

            <div className="flex-1 bg-surface/30 border border-gold/20 rounded-lg p-6 md:p-10 min-h-[400px] relative">
                {/* Decorative corners */}
                <div className="absolute top-0 left-0 w-4 h-4 border-t border-l border-gold/40"></div>
                <div className="absolute top-0 right-0 w-4 h-4 border-t border-r border-gold/40"></div>
                <div className="absolute bottom-0 left-0 w-4 h-4 border-b border-l border-gold/40"></div>
                <div className="absolute bottom-0 right-0 w-4 h-4 border-b border-r border-gold/40"></div>

                <div className="font-serif text-gold/90 text-lg leading-relaxed space-y-6">
                    <p className="animate-pulse">
                        The cards have been laid out before you. The universe is whispering its secrets...
                    </p>
                    <p className="opacity-50 text-base">
                        (AI Interpretation API to be integrated here. Once connected, this section will generate a detailed reading based on the combination of {results.map(r => getCardDetails(r.cardId)?.nameEn).join(', ')}.)
                    </p>
                </div>
            </div>
        </div>

      </div>
    </div>
  );
};

export default InterpretationScreen;

